import React, { useState, useEffect } from 'react';
import axios from 'axios';

const StockMovementForm = ({ refreshMovements }) => {
    const [movement, setMovement] = useState({
        produto: '',
        tipo_movimentacao: 'entrada',
        quantidade: '',
        motivo: ''
    });

    const [products, setProducts] = useState([]); // Armazena a lista de produtos

    useEffect(() => {
        const fetchProducts = async () => {
            try {
                const response = await axios.get('http://127.0.0.1:8000/api/produtos/');
                setProducts(response.data);
            } catch (error) {
                console.error("Erro ao buscar produtos:", error);
            }
        };

        fetchProducts(); // Busca a lista de produtos ao montar o componente
    }, []);

    const handleChange = (e) => {
        setMovement({ ...movement, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        try {
            // Envia a movimentação para o backend
            await axios.post('http://127.0.0.1:8000/api/movimentacoes/', {
                produto: movement.produto,
                tipo_movimentacao: movement.tipo_movimentacao,
                quantidade: parseInt(movement.quantidade), // Certifique-se de que a quantidade é um número
                motivo: movement.motivo
            });
            refreshMovements(); // Atualiza a lista de movimentações
            setMovement({ produto: '', tipo_movimentacao: 'entrada', quantidade: '', motivo: '' }); // Limpa o formulário
        } catch (error) {
            console.error("Erro ao registrar movimentação:", error);
        }
    };

    return (
        <form onSubmit={handleSubmit}>
            <select name="produto" onChange={handleChange} required value={movement.produto}>
                <option value="">Selecione um produto</option>
                {products.map((product) => (
                    <option key={product.id} value={product.id}>
                        {product.nome}
                    </option>
                ))}
            </select>
            <select name="tipo_movimentacao" onChange={handleChange} required value={movement.tipo_movimentacao}>
                <option value="entrada">Entrada</option>
                <option value="saida">Saída</option>
            </select>
            <input type="number" name="quantidade" placeholder="Quantidade" onChange={handleChange} required value={movement.quantidade} />
            <input name="motivo" placeholder="Motivo" onChange={handleChange} value={movement.motivo} />
            <button type="submit">Registrar Movimentação</button>
        </form>
    );
};

export default StockMovementForm;
